var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳, 한 가지 묻고 싶은 게 있어요.","JPN":"リベット、一つ聞いてもよろしいですか？","ENG":"Rivet, there's a question I'd like to ask you.","TWN":"里維，我有個問題想問妳。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"두 가지 물어봐도 돼~ 친절한 리벳 선생님이 정답을 콕콕 찔러 줄 테니까~","JPN":"二つ聞いてもいいよ～。親切なリベット先生が正解を教えてあげるからさ～。","ENG":"You can ask two if you want. Ms. Rivet here will answer you kindly.","TWN":"問兩個也可以喔～親切的里維老師會一一告訴妳正確答案的～"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"일단 그 정신 사나운 쇳덩어리부터 내려놓고 이야기하죠.","JPN":"とりあえず、その物騒な鉄の塊を下ろしてから話しましょう。","ENG":"Will you put down that bulky metal chunk first please?","TWN":"總之先從那個兇殘的鐵塊開始說起吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"쇳덩어리라니 너무하네. 얘가 들으면 얼마나 서운해 하겠어.","JPN":"鉄の塊って酷い言い草だね。この子が聞いたら悲しむよ。","ENG":"Hey, that's rude. She's going to find it very offensive.","TWN":"竟然說是鐵塊，太過分了。這孩子聽見了會有多難過啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......설마 인공지능 모듈이라도 장착되어 있는 무기인가요?","JPN":"……まさか、人工知能モジュールでも搭載された武器なのですか？","ENG":"Oh, I didn't know it was equipped with an A.I. module.","TWN":"……那武器該不會是裝載了人工智慧模組吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아니? 그런 거 전혀 없는 완전 구식 쇳덩어린데?★","JPN":"ううん。そんなの一つも付いてない、超旧式な鉄の塊だけど？★","ENG":"It's not. It's a plain old chunk of metal. ★","TWN":"不是喔？完全沒有這種東西，完全是個舊式鐵塊喔？★"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......그래요. 그럴 줄 알았어요.","JPN":"……ですよね。そうだろうと思っていました。","ENG":"Okay. I thought so.","TWN":"……是嗎，我就知道。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그나저나, 언제부터 이 숲에 침식체들이 나타나기 시작했죠?","JPN":"ところで、いつからこの森に侵食体が現れ始めたのですか？","ENG":"My question is, when did Corrupted Objects start appearing in the forest?","TWN":"不過，這片森林裡是什麼時候開始出現侵蝕體的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 없는 동안 이 근방에 침식 재난 경보령이라도 발령됐나요?","JPN":"私がいない間に、この辺りに侵食災害警報でも発令されたのですか？","ENG":"Did they declare this place a Corruption Disaster area while I was gone?","TWN":"我不在的時候，周圍有發佈侵蝕災難警報嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"뿌뿌뿝. 틀렸습니다. 레지나 학생.","JPN":"ブッブー。ハズレですね、レジーナくん。","ENG":"Bzzzzt! You're incorrect, Regina.","TWN":"噗噗，答錯囉，蕾佳娜同學。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"경보령 같은 거 발령된 적 없으니까 심각한 표정 짓지 마.","JPN":"警報なんて発令されてないから、そんな険しい顔しないでよ。","ENG":"That never happened, so you don't have to look so serious.","TWN":"沒有發佈什麼警報，所以別一臉嚴肅的樣子嘛。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그냥 해가 지면 하급 침식체들이 어슬렁거리는 정도야.","JPN":"日が暮れたら下級侵食体がうろつく程度だからさ。","ENG":"When the sun goes down, those low class C.O.s come out for a stroll. That's all.","TWN":"只是太陽下山後，會有低等侵蝕體出來閒晃而已。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그게 그거잖아요! 침식체가 나타나면 경보령도 발령되겠죠!","JPN":"つまり、侵食体が日常的に現れるということですわね？\\n侵食体が現れたならば、警報が発令されるはずですわ！","ENG":"How is that any less concerning? They declare areas where there are Corrupted Objects disaster areas!","TWN":"那不就是嘛！有侵蝕體出現的話，就會發佈警報啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"관리국이 정식으로 선포한 적 없는데 어쩌겠어. 리플레이서 사태 때문에 여력이 없나 보지.","JPN":"管理局が正式に宣布しないんだから仕方ないよ。\\nリプレイサー騒動で忙しいんだろうね。","ENG":"Whatever you say, it was never made official by the Administration. Maybe they have their hands full because of the Replacer incident.","TWN":"管理局沒有正式宣佈過，又能怎麼辦呢。看來是因為克隆集團的事件，他們沒有餘力管這些了吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만......","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"걱정 마. 여기 침식체들은 숲에서만 돌아다니고 사람 사는 데까지 쳐들어오진 않거든.","JPN":"心配いらないよ。ここの侵食体たちは\\n森から出ることも、人の住んでるところに現れることもないから。","ENG":"Don't worry. The C.O.s here don't raid houses; all they do is roam the forest.","TWN":"別擔心。這裡的侵蝕體只會在樹林裡徘徊，不會入侵人們生活的地方。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"고로 밤 늦게 돌아다니지만 않으면 안전해. 나 같은 용병에겐 완전 좋은 일이지.","JPN":"夜遅くに歩き回らなければ安全ってこと。アタシみたいな傭兵にはありがたいことだけどね。","ENG":"So you're safe if you stay home during the night. They're actually making things easier for mercenaries like me.","TWN":"所以只要晚上不要到這裡就很安全。對我這種傭兵來說，完全是件好事啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네? 그건 또 무슨 뜻이죠?","JPN":"それはどういう意味ですの？","ENG":"Huh? What’s that supposed to mean?","TWN":"咦？這又是什麼意思？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"움직이는 건 뭐든 쏴 버려도 오발 사고 걱정할 필요 없으니까.","JPN":"動くものを見つけたら、確認しないで撃っても誤射する心配が無いからさ。","ENG":"I can open fire at anything that's moving without having to worry about accidents.","TWN":"因為即使看到有東西在動就開槍，也不會發生誤射意外啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};